firmware_template.source:
#include "lis3dh.h"
#include <Wire.h>
#include <Adafruit_LIS3DH.h>
#include <Adafruit_Sensor.h>
static Adafruit_LIS3DH lis;
static float _x=0,_y=0,_z=0;
static bool _tap=false;
static unsigned long _last=0;
void lis3dh_setup(){Wire.begin();if(!lis.begin(0x18)){Serial.println("[lis3dh] Fail!");return;}lis.setRange(LIS3DH_RANGE_4_G);lis.setClick(2,80);Serial.println("[lis3dh] OK");}
void lis3dh_loop(){if(millis()-_last<50)return;_last=millis();lis.read();sensors_event_t e;lis.getEvent(&e);_x=e.acceleration.x;_y=e.acceleration.y;_z=e.acceleration.z;_tap=(lis.getClick()>0);}
float lis3dh_get_x(){return _x;}
float lis3dh_get_y(){return _y;}
float lis3dh_get_z(){return _z;}
bool lis3dh_tap_detected(){return _tap;}
